SELECT COUNT(*) AS active_webpage_count
FROM webpages
WHERE is_active = 1;

SELECT reputation_score
FROM reputation_scores
WHERE reputation_score > 0.5;

SELECT title
FROM webpages
WHERE webpage_id = 1;

SELECT category_description
FROM categories
ORDER BY category_description;

SELECT title
FROM webpages
WHERE reputation_score > 0.8;

SELECT title, reputation_score 
FROM webpages 
ORDER BY reputation_score DESC;
